function getNeighboringCoordinates(x: number, y: number): [number, number][] {
  const neighbors: [number, number][] = [];
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      neighbors.push([x + dx, y + dy]);
    }
  }
  return neighbors;
}

export function nextGeneration(grid: Set<[number, number]>): Set<[number, number]> {
  if (grid.size === 0) {
    return new Set();
  }

  const result = new Set<[number, number]>();
  const cellsToCheck = new Set<string>();

  // Collect all cells to check (living + neighbors of living cells)
  for (const [x, y] of grid) {
    cellsToCheck.add(`${x},${y}`);
    for (const [nx, ny] of getNeighboringCoordinates(x, y)) {
      cellsToCheck.add(`${nx},${ny}`);
    }
  }

  // Apply Game of Life rules
  for (const cellStr of cellsToCheck) {
    const [x, y] = cellStr.split(',').map(Number) as [number, number];
    const neighbors = countNeighbors(x, y, grid);
    const isAlive = grid.has([x, y]);

    if (isAlive && (neighbors === 2 || neighbors === 3)) {
      result.add([x, y]);
    } else if (!isAlive && neighbors === 3) {
      result.add([x, y]);
    }
  }

  return result;
}

